import assert from 'node:assert/strict';
import { spawn, spawnSync } from 'node:child_process';
import dgram from 'node:dgram';
import { once } from 'node:events';
import { chmodSync, mkdtempSync, rmSync, writeFileSync } from 'node:fs';
import { createServer } from 'node:http';
import { tmpdir } from 'node:os';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { afterEach, describe, it } from 'node:test';
import {
  aeonMonitorBinaryCandidates,
  formatDelegationEnvelope,
  parseMonsterMeshArgv,
  profileEnvForDelegation,
  resolveMonsterMeshBackend,
} from './wrapper-mesh-delegation.mjs';

const gnosisFixtureRoot = join(dirname(fileURLToPath(import.meta.url)), '..');
const flowHeaderSize = 10;
const flowFlagsForkRaceFoldVent = 0b0000_1111;

function encodeFlowFrame(payload, sequence = 0) {
  const payloadBytes = Buffer.from(payload);
  const frame = Buffer.alloc(flowHeaderSize + payloadBytes.length);
  frame.writeUInt16BE(1, 0);
  frame.writeUInt32BE(sequence, 2);
  frame[6] = flowFlagsForkRaceFoldVent;
  frame[7] = (payloadBytes.length >> 16) & 0xff;
  frame[8] = (payloadBytes.length >> 8) & 0xff;
  frame[9] = payloadBytes.length & 0xff;
  payloadBytes.copy(frame, flowHeaderSize);
  return frame;
}

function decodeFlowFramePayload(frame) {
  const payloadLength = (frame[7] << 16) | (frame[8] << 8) | frame[9];
  return frame.subarray(flowHeaderSize, flowHeaderSize + payloadLength).toString('utf8');
}

async function startProtocol69ProbeServer() {
  const projection = {
    schemaVersion: 'gnosis.protocol69.v1',
    protocol: 'protocol69',
    wordName: 'sixty9',
    mode: 'monster-number',
    magic: 'GNOSIS-MONSTER-NUMBER/1',
    broadcastSymbol: 66,
    localFoilOperand: 7,
    operator: 'xor',
    expectedProjection: 69,
    ascii: 'GNOSIS-MONSTER-NUMBER/1 protocol=protocol69 wordName=sixty9 broadcastSymbol=66 localFoilOperand=7 operator=xor expectedProjection=69',
  };
  const http = createServer((_request, response) => {
    response.writeHead(200, { 'Content-Type': 'application/json' });
    response.end(JSON.stringify({ status: 'validated', projection }));
  });
  const udp = dgram.createSocket('udp4');
  udp.on('message', (message, remote) => {
    const path = decodeFlowFramePayload(message);
    const body = JSON.stringify({
      status: path === '/.aeon/protocol69' ? 'ok' : 'not_found',
      projection,
    });
    udp.send(encodeFlowFrame(body), remote.port, remote.address);
  });
  const httpListening = once(http, 'listening');
  const udpListening = once(udp, 'listening');
  http.listen(0, '127.0.0.1');
  udp.bind(0, '127.0.0.1');
  await httpListening;
  await udpListening;
  return {
    httpUrl: `http://127.0.0.1:${http.address().port}/.aeon/protocol69`,
    flowPort: udp.address().port,
    close: async () => {
      const httpClosed = once(http, 'close');
      const udpClosed = once(udp, 'close');
      http.close();
      udp.close();
      await httpClosed;
      await udpClosed;
    },
  };
}

function spawnNode(args, options) {
  return new Promise((resolve) => {
    const child = spawn(process.execPath, args, options);
    let stdout = '';
    let stderr = '';
    child.stdout.setEncoding('utf8');
    child.stderr.setEncoding('utf8');
    child.stdout.on('data', (chunk) => {
      stdout += chunk;
    });
    child.stderr.on('data', (chunk) => {
      stderr += chunk;
    });
    child.on('close', (status) => {
      resolve({ status, stdout, stderr });
    });
  });
}

describe('parseMonsterMeshArgv', () => {
  it('strips mesh-backend and profile, forwards the rest', () => {
    const r = parseMonsterMeshArgv([
      '--mesh-backend',
      'host',
      '--profile',
      'ism433',
      'extra',
    ]);
    assert.deepEqual(r.rest, ['extra']);
    assert.equal(r.meshBackend, 'host');
    assert.equal(r.profile, 'ism433');
  });

  it('passes through when flags absent', () => {
    const r = parseMonsterMeshArgv(['a', 'b']);
    assert.deepEqual(r.rest, ['a', 'b']);
    assert.equal(r.meshBackend, null);
    assert.equal(r.profile, null);
  });
});

describe('resolveMonsterMeshBackend', () => {
  afterEach(() => {
    delete process.env.GNOSIS_MONSTER_MESH_BACKEND;
    delete process.env.GNOSIS_AEON_MONITOR_BIN;
  });

  it('respects explicit host over env', () => {
    process.env.GNOSIS_MONSTER_MESH_BACKEND = 'service';
    assert.equal(resolveMonsterMeshBackend('host', gnosisFixtureRoot), 'host');
  });

  it('respects explicit service', () => {
    assert.equal(resolveMonsterMeshBackend('service', gnosisFixtureRoot), 'service');
  });

  it('uses env when CLI omits backend', () => {
    process.env.GNOSIS_MONSTER_MESH_BACKEND = 'service';
    assert.equal(resolveMonsterMeshBackend(null, gnosisFixtureRoot), 'service');
  });

  it('throws on invalid backend string', () => {
    assert.throws(() => resolveMonsterMeshBackend('bogus', gnosisFixtureRoot));
  });
});

describe('profileEnvForDelegation', () => {
  it('maps ism433', () => {
    const e = profileEnvForDelegation('ism433');
    assert.equal(e.GNOSIS_MESH_PROFILE, 'ism433');
    assert.equal(e.GNOSIS_MESH_CENTER_MHZ, '433.92');
  });

  it('returns empty for unknown profile', () => {
    assert.deepEqual(profileEnvForDelegation('unknown'), {});
  });
});

describe('formatDelegationEnvelope', () => {
  it('includes schemaVersion and opaque version field for service payloads', () => {
    const j = JSON.parse(
      formatDelegationEnvelope('service', 'ism915', {
        version: 'fat-station.health.v1',
        stations: [],
      }),
    );
    assert.equal(j.delegatedMonsterMesh.schemaVersion, 'monster-mesh.delegation.v1');
    assert.equal(j.delegatedMonsterMesh.backend, 'service');
    assert.equal(j.delegatedMonsterMesh.profile, 'ism915');
    assert.equal(j.delegatedMonsterMesh.opaque.version, 'fat-station.health.v1');
  });
});

describe('aeonMonitorBinaryCandidates', () => {
  afterEach(() => {
    delete process.env.GNOSIS_AEON_MONITOR_BIN;
  });

  it('uses only GNOSIS_AEON_MONITOR_BIN when set', () => {
    process.env.GNOSIS_AEON_MONITOR_BIN = '/opt/aeon-monitor';
    const c = aeonMonitorBinaryCandidates(gnosisFixtureRoot);
    assert.deepEqual(c, ['/opt/aeon-monitor']);
  });
});

describe('rf-key CLI', () => {
  it('emits the simulated Monster RF cache-key replay envelope', () => {
    const wrapper = join(gnosisFixtureRoot, 'bin', 'rtlsdr-mock-sim.js');
    const result = spawnSync(process.execPath, [wrapper, 'rf-key'], {
      cwd: gnosisFixtureRoot,
      encoding: 'utf8',
    });

    assert.equal(result.status, 0, result.stderr);
    const parsed = JSON.parse(result.stdout);
    const envelope = parsed.monsterRfCacheKey;

    assert.equal(envelope.schemaVersion, 'gnosis.rf-cache-key.v1');
    assert.equal(envelope.transport, 'simulated');
    assert.equal(envelope.broadcaster.txAvailable, true);
    assert.equal(envelope.receiver.healthy, true);
    assert.equal(envelope.frame.packet.prefixHash, 66);
    assert.equal(envelope.frame.packet.prefixLen, 7);
    assert.equal(envelope.frame.packet.stationCount, 2);
    assert.equal(envelope.replayContract.cachedReplay, true);
    assert.equal(envelope.replayContract.geodesicLength, 0);
    assert.match(envelope.frame.ascii, /^GNOSIS-RFKEY\/1 /);
    assert.match(envelope.frame.ascii, /crc16=[0-9a-f]{4}$/);
  });

  it('emits protocol69 monster-number projection mode', () => {
    const wrapper = join(gnosisFixtureRoot, 'bin', 'rtlsdr-mock-sim.js');
    const result = spawnSync(
      process.execPath,
      [wrapper, 'rf-key', '--symbol-mode', 'monster-number'],
      {
        cwd: gnosisFixtureRoot,
        encoding: 'utf8',
      },
    );

    assert.equal(result.status, 0, result.stderr);
    const parsed = JSON.parse(result.stdout);
    const projection = parsed.monsterRfCacheKey.projection;

    assert.equal(projection.protocol, 'protocol69');
    assert.equal(projection.mode, 'monster-number');
    assert.equal(projection.broadcastSymbol, 66);
    assert.equal(projection.localFoilOperand, 7);
    assert.equal(projection.operator, 'xor');
    assert.equal(projection.expectedProjection, 69);
    assert.match(projection.ascii, /^GNOSIS-MONSTER-NUMBER\/1 /);
  });

  it('certifies protocol69 against FOIL HTTP and Flow probe endpoints', async () => {
    const server = await startProtocol69ProbeServer();
    try {
      const wrapper = join(gnosisFixtureRoot, 'bin', 'rtlsdr-mock-sim.js');
      const result = await spawnNode(
        [
          wrapper,
          'rf-key',
          '--symbol-mode',
          'monster-number',
          '--protocol69-foil-probe',
          '--protocol69-foil-transport',
          'both',
          '--protocol69-foil-url',
          server.httpUrl,
          '--protocol69-flow-host',
          '127.0.0.1',
          '--protocol69-flow-port',
          String(server.flowPort),
          '--protocol69-timeout-ms',
          '10000',
        ],
        {
          cwd: gnosisFixtureRoot,
        },
      );

      assert.equal(result.status, 0, result.stderr || result.stdout);
      const parsed = JSON.parse(result.stdout);
      const probe = parsed.monsterRfCacheKey.protocol69FoilProbe;

      assert.equal(probe.protocol, 'protocol69');
      assert.equal(probe.transport, 'both');
      assert.equal(probe.ok, true);
      assert.equal(probe.http.ok, true);
      assert.equal(probe.flowUdp.ok, true);
      assert.equal(probe.http.response.projection.expectedProjection, 69);
      assert.equal(probe.flowUdp.response.projection.wordName, 'sixty9');

      const admission = parsed.monsterRfCacheKey.protocol69FoilAdmission;
      assert.equal(
        admission.certificateVersion,
        'gnosis.protocol69.foil-admission.v1',
      );
      assert.equal(admission.protocol, 'protocol69');
      assert.equal(admission.wordName, 'sixty9');
      assert.equal(admission.source, 'monster-rf-cache-key');
      assert.equal(admission.projectionAccepted, true);
      assert.equal(admission.requiredTransport, 'both');
      assert.equal(admission.httpAccepted, true);
      assert.equal(admission.flowUdpAccepted, true);
      assert.equal(admission.broadcastSymbol, 66);
      assert.equal(admission.localFoilOperand, 7);
      assert.equal(admission.expectedProjection, 69);
      assert.deepEqual(admission.theoremRefs, [
        'Gnosis.RemoteCacheKeyTeleportation.protocol69_monster_number_projection',
        'Gnosis.RemoteCacheKeyTeleportation.protocol69_braids_integer_projection_with_fano_parity',
      ]);
    } finally {
      await server.close();
    }
  });

  it('emits a dry-run SoapySDR Pluto+ TX adapter without executing TX', () => {
    const tempRoot = mkdtempSync(join(tmpdir(), 'gnosis-rtl-test-'));
    try {
      const rtlTest = join(tempRoot, 'rtl_test');
      writeFileSync(
        rtlTest,
        [
          '#!/bin/sh',
          'echo "Found 1 device(s):" >&2',
          'echo "  0: Nooelec, NESDR SMArt v5, SN: 78922015" >&2',
          'exit 0',
          '',
        ].join('\n'),
      );
      chmodSync(rtlTest, 0o755);
      const soapy = join(tempRoot, 'SoapySDRUtil');
      writeFileSync(
        soapy,
        [
          '#!/bin/sh',
          'echo "Found device 0"',
          'echo "  driver=plutosdr"',
          'exit 0',
          '',
        ].join('\n'),
      );
      chmodSync(soapy, 0o755);

      const wrapper = join(gnosisFixtureRoot, 'bin', 'rtlsdr-mock-sim.js');
      const result = spawnSync(
        process.execPath,
        [
          wrapper,
          'rf-key',
          '--transport',
          'hardware',
          '--rtl-test-bin',
          rtlTest,
          '--tx-kind',
          'soapy-sdr-tx',
          '--tx-bin',
          soapy,
          '--tx-device-args',
          'driver=plutosdr',
          '--preflight-only',
        ],
        {
          cwd: gnosisFixtureRoot,
          encoding: 'utf8',
        },
      );

      assert.equal(result.status, 0, result.stderr);
      const parsed = JSON.parse(result.stdout);
      const rfKey = parsed.monsterRfCacheKey;
      const adapter = rfKey.broadcaster.adapter;

      assert.equal(rfKey.transport, 'hardware');
      assert.equal(rfKey.broadcaster.txAvailable, true);
      assert.equal(rfKey.receiver.healthy, true);
      assert.deepEqual(rfKey.receiver.deviceSerials, ['78922015']);
      assert.equal(adapter.kind, 'soapy-sdr-tx');
      assert.equal(adapter.binary, soapy);
      assert.equal(adapter.centerFrequencyHz, 433_920_000);
      assert.equal(adapter.sampleRateHz, 2_000_000);
      assert.equal(adapter.gainDb, 0);
      assert.deepEqual(adapter.argv, [
        '--device',
        'driver=plutosdr',
        '--rate',
        '2000000',
        '--freq',
        '433920000',
        '--gain',
        '0',
        '--stdin-ascii-frame',
      ]);
      assert.match(adapter.stdinFrame, /^GNOSIS-RFKEY\/1 /);
      assert.equal(adapter.discovery.hardwarePresent, true);
      assert.deepEqual(adapter.discovery.argv, ['--find=driver=plutosdr']);
      assert.equal(Object.hasOwn(parsed, 'txExecution'), false);
    } finally {
      rmSync(tempRoot, { recursive: true, force: true });
    }
  });

  it('captures a mocked RTL receiver window for the RF cache-key band', () => {
    const tempRoot = mkdtempSync(join(tmpdir(), 'gnosis-rtl-rx-test-'));
    try {
      const rtlTest = join(tempRoot, 'rtl_test');
      writeFileSync(
        rtlTest,
        [
          '#!/bin/sh',
          'echo "Found 1 device(s):" >&2',
          'echo "  0: Nooelec, NESDR SMArt v5, SN: 94092559" >&2',
          'exit 0',
          '',
        ].join('\n'),
      );
      chmodSync(rtlTest, 0o755);
      const rtlSdr = join(tempRoot, 'rtl_sdr');
      writeFileSync(
        rtlSdr,
        [
          '#!/bin/sh',
          'out="$7"',
          'python3 - "$out" <<PY',
          'import sys',
          'open(sys.argv[1], "wb").write(bytes([160, 128]) * 8)',
          'PY',
          'exit 0',
          '',
        ].join('\n'),
      );
      chmodSync(rtlSdr, 0o755);
      const captureOut = join(tempRoot, 'rf-key-window.u8');
      const wrapper = join(gnosisFixtureRoot, 'bin', 'rtlsdr-mock-sim.js');
      const result = spawnSync(
        process.execPath,
        [
          wrapper,
          'rf-key',
          '--transport',
          'hardware',
          '--rtl-test-bin',
          rtlTest,
          '--rtl-sdr-bin',
          rtlSdr,
          '--rx-capture-only',
          '--rx-capture-out',
          captureOut,
          '--rx-samples',
          '8',
          '--preflight-only',
        ],
        {
          cwd: gnosisFixtureRoot,
          encoding: 'utf8',
        },
      );

      assert.equal(result.status, 0, result.stderr);
      const parsed = JSON.parse(result.stdout);
      const receiver = parsed.monsterRfCacheKey.receiver;

      assert.equal(receiver.healthy, true);
      assert.deepEqual(receiver.deviceSerials, ['94092559']);
      assert.equal(receiver.capture.ok, true);
      assert.equal(receiver.capture.outputPath, captureOut);
      assert.equal(receiver.capture.centerFrequencyHz, 433_920_000);
      assert.equal(receiver.capture.sampleRateHz, 2_000_000);
      assert.equal(receiver.capture.samplePairs, 8);
      assert.equal(receiver.capture.byteLength, 16);
      assert.equal(receiver.capture.energy.iqPairs, 8);
      assert.equal(receiver.capture.energy.energyDetected, true);
      assert.equal(receiver.capture.energy.rmsMagnitude, 0.25);
      assert.deepEqual(receiver.capture.argv.slice(0, 6), [
        '-f',
        '433920000',
        '-s',
        '2000000',
        '-n',
        '8',
      ]);
    } finally {
      rmSync(tempRoot, { recursive: true, force: true });
    }
  });
});
